function translateUiStringToEnglish(value) {
  let out = String(value || '');
  for (const [pattern, replacement] of UI_FR_TO_EN_REPLACEMENTS) out = out.replace(pattern, replacement);
  return out;
}

function translateEmbedForUi(guildConfig, embed) {
  if (isFrenchUi(guildConfig) || !embed?.data) return embed;
  const walk = (value) => {
    if (typeof value === 'string') return translateUiStringToEnglish(value);
    if (Array.isArray(value)) return value.map(walk);
    if (value && typeof value === 'object') { for (const key of Object.keys(value)) value[key] = walk(value[key]); }
    return value;
  };
  walk(embed.data);
  return embed;
}


function polishGuildPanelEmbed(embed, guild, sectionLabel = 'Neyora') {
  if (!embed?.setAuthor) return embed;
  const iconURL = guild?.iconURL?.({ size: 256 }) || guild?.iconURL?.() || null;
  if (guild?.name) embed.setAuthor({ name: `${guild.name} • ${sectionLabel}`.slice(0, 256), iconURL: iconURL || undefined });
  if (iconURL && !embed.data?.thumbnail && !embed.data?.image) embed.setThumbnail(iconURL);
  return embed;
}

function uiState(enabled, onLabel = 'on', offLabel = 'off') {
  return `${enabled ? '🟢' : '🔴'} ${enabled ? onLabel : offLabel}`;
}

function uiBool(enabled, yesLabel = 'yes', noLabel = 'no') {
  return `${enabled ? '✅' : '❌'} ${enabled ? yesLabel : noLabel}`;
}

function uiChannel(id, fallback = 'not set') {
  return id ? `<#${id}>` : fallback;
}

function uiRole(id, fallback = 'not set') {
  return id ? `<@&${id}>` : fallback;
}

function cleanLines(lines, fallback = '—') {
  if (Array.isArray(lines)) {
    const joined = lines
      .filter((line) => line !== null && line !== undefined && String(line).trim().length)
      .join('\n')
      .trim();
    return (joined || fallback).slice(0, 1024);
  }
  const value = String(lines || '').trim();
  return (value || fallback).slice(0, 1024);
}

function sectionField(name, lines, inline = false) {
  return { name, value: cleanLines(lines), inline };
}

function metricLine(label, value) {
  return `• **${label}** → ${value}`;
}

function commandPill(prefix, usage) {
  return `\`${prefix}${usage}\``;
}

function hubBadge(guildConfig, emoji, fr, en, value) {
  return `${emoji} **${uiText(guildConfig, fr, en)}** • ${value}`;
}

function applyHubFrame(embed, guildConfig, guild, sectionFr, sectionEn, summaryLines = []) {
  const summary = Array.isArray(summaryLines) ? summaryLines.filter(Boolean) : [summaryLines].filter(Boolean);
  if (summary.length) embed.setDescription(cleanLines(summary, embed.data?.description || '—').slice(0, 4096));
  return polishGuildPanelEmbed(embed, guild, uiText(guildConfig, sectionFr, sectionEn));
}

