function normalizeLogToken(value) {
  return String(value || '').toLowerCase().replace(/[^a-z0-9]/g, '');
}

function getLogTypeLabel(type) {
  return LOG_TYPE_CHOICES.find(([value]) => value === type)?.[1] || type;
}

function resolveLogTarget(value) {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const token = normalizeLogToken(raw);
  const family = LOG_GROUP_ALIASES[token];
  if (family) {
    return {
      kind: family === 'default' ? 'default' : 'family',
      key: family,
      label: family === 'default' ? 'Default route' : (LOG_CHANNEL_GROUPS.find((group) => group.key === family)?.label || family)
    };
  }
  const type = LOG_TYPE_CHOICES.find(([key]) => normalizeLogToken(key) === token)?.[0] || LOG_TYPE_ALIASES[token] || null;
  if (type) return { kind: 'type', key: type, label: getLogTypeLabel(type) };
  return null;
}

function getTypesForLogTarget(target) {
  if (!target) return [];
  if (target.kind === 'type') return [target.key];
  if (target.kind === 'family') return LOG_CHANNEL_GROUPS.find((group) => group.key === target.key)?.types || [];
  if (target.kind === 'default') return LOG_TYPE_CHOICES.map(([key]) => key);
  return [];
}

function getLogRouteKeyForType(type) {
  return LOG_CHANNEL_GROUPS.find((group) => group.types.includes(type))?.key || 'default';
}

function getResolvedLogChannelId(logs, type) {
  const typeSalons = logs?.typeSalons || {};
  const routeSalons = logs?.channels || {};
  return typeSalons[type] || routeSalons[getLogRouteKeyForType(type)] || routeSalons.default || logs?.channelId || null;
}

function isLogsTextChannel(channel) {
  return Boolean(channel && [ChannelType.GuildText, ChannelType.GuildAnnouncement].includes(channel.type));
}

function splitLinesForField(lines, chunkSize = 8) {
  const chunks = [];
  for (let i = 0; i < lines.length; i += chunkSize) chunks.push(lines.slice(i, i + chunkSize));
  return chunks;
}


function createLogsOverviewEmbed(guildConfig, prefix = '+') {
  const logs = guildConfig.logs || { enabled: false, channelId: null, channels: {}, typeSalons: {}, types: {} };
  const defaultChannelId = logs.channels?.default || logs.channelId || null;
  const noRoute = uiText(guildConfig, 'utilise la route par défaut', 'uses the default route');
  const notSet = uiText(guildConfig, 'non défini', 'not set');
  const familyLabelMap = {
    messages: uiText(guildConfig, 'Messages', 'Messages'),
    members: uiText(guildConfig, 'Membres / invites / boosts', 'Members / invites / boosts'),
    moderation: uiText(guildConfig, 'Modération / sécurité', 'Moderation / security'),
    voice: uiText(guildConfig, 'Vocal', 'Voice'),
    server: uiText(guildConfig, 'Serveur / rôles / salons', 'Server / roles / channels'),
    social: uiText(guildConfig, 'Support / TikTok / invites', 'Support / TikTok / invite codes')
  };
  const familyLines = LOG_CHANNEL_GROUPS.map((group) => metricLine(familyLabelMap[group.key] || group.label, logs.channels?.[group.key] ? `<#${logs.channels[group.key]}>` : noRoute));
  const typeOverrides = Object.entries(logs.typeSalons || {})
    .filter(([, channelId]) => Boolean(channelId))
    .map(([type, channelId]) => metricLine(getLogTypeLabel(type), `<#${channelId}>`))
    .sort((a, b) => a.localeCompare(b));
  const enabledTypes = LOG_TYPE_CHOICES.filter(([type]) => logs.types?.[type] !== false).map(([type]) => type);
  const disabledTypes = LOG_TYPE_CHOICES.filter(([type]) => logs.types?.[type] === false).map(([type]) => `• ${getLogTypeLabel(type)}`);
  const routedFamilies = Object.entries(logs.channels || {}).filter(([key, value]) => key !== 'default' && Boolean(value)).length;

  const embed = baseEmbed(
    guildConfig,
    uiText(guildConfig, '🧾 Hub logs', '🧾 Logs hub'),
    [
      uiText(guildConfig, 'Vue claire pour comprendre le switch global, la route par défaut, les familles et les exceptions par type.', 'Clean view to understand the global switch, the default route, families and direct per-type overrides.'),
      '',
      hubBadge(guildConfig, '📍', 'Switch global', 'Global switch', uiState(logs.enabled, uiText(guildConfig, 'actif', 'enabled'), uiText(guildConfig, 'inactif', 'disabled'))),
      hubBadge(guildConfig, '🧭', 'Route par défaut', 'Default catch-all route', defaultChannelId ? `<#${defaultChannelId}>` : notSet),
      hubBadge(guildConfig, '🗂️', 'Familles routées', 'Routed families', String(routedFamilies)),
      hubBadge(guildConfig, '🎯', 'Exceptions par type', 'Per-type overrides', String(typeOverrides.length))
    ].join('\n')
  );

  embed.addFields(
    sectionField(uiText(guildConfig, '⚡ Démarrage rapide', '⚡ Quick start'), [
      `1. \`${prefix}logs quicksetup\` ${uiText(guildConfig, '→ crée les salons logs', '→ create the log channels')}`,
      `2. \`${prefix}logs global on\` ${uiText(guildConfig, '→ active tout le module', '→ enable the whole module')}`,
      `3. \`${prefix}logs boost here\` ${uiText(guildConfig, 'ou', 'or')} \`${prefix}logs messages #message-logs\``,
      `4. \`${prefix}logs test boost\` ${uiText(guildConfig, '→ vérifie une route précise', '→ verify one exact route')}`
    ], true),
    sectionField(uiText(guildConfig, '🧠 Comment ça marche', '🧠 How it works'), [
      `• ${uiText(guildConfig, 'switch global', 'global switch')} = ${uiText(guildConfig, 'coupe ou autorise tous les logs', 'cuts or allows every log')}`,
      `• ${uiText(guildConfig, 'route par défaut', 'default route')} = ${uiText(guildConfig, 'fallback pour les types sans route dédiée', 'fallback for types without a dedicated route')}`,
      `• ${uiText(guildConfig, 'famille', 'family')} = ${uiText(guildConfig, 'groupe de logs comme messages, vocal ou support', 'a group like messages, voice or support')}`,
      `• ${uiText(guildConfig, 'exception par type', 'per-type override')} = ${uiText(guildConfig, 'passe avant la famille', 'wins over the family route')}`
    ], true),
    sectionField(uiText(guildConfig, '🧭 Familles', '🧭 Families'), familyLines, false)
  );

  if (typeOverrides.length) {
    const chunks = splitLinesForField(typeOverrides, 10);
    chunks.forEach((chunk, index) => embed.addFields(sectionField(
      index === 0 ? uiText(guildConfig, '🎯 Exceptions par type', '🎯 Per-type overrides') : uiText(guildConfig, '🎯 Exceptions par type • suite', '🎯 Per-type overrides • more'),
      chunk,
      false
    )));
  }

  if (disabledTypes.length) {
    const chunks = splitLinesForField(disabledTypes, 14);
    chunks.forEach((chunk, index) => embed.addFields(sectionField(
      index === 0 ? uiText(guildConfig, '⏸️ Types coupés', '⏸️ Disabled event types') : uiText(guildConfig, '⏸️ Types coupés • suite', '⏸️ Disabled event types • more'),
      chunk,
      false
    )));
  }

  embed.addFields(sectionField(uiText(guildConfig, '💡 Commandes utiles', '💡 Useful commands'), [
    `• \`${prefix}logs panel\` ${uiText(guildConfig, '→ panel boutons pour les familles', '→ button panel for families')}`,
    `• \`${prefix}logs guide\` ${uiText(guildConfig, '→ explication simple du système logs', '→ simple explanation of the logs system')}`,
    `• \`${prefix}logs types\` ${uiText(guildConfig, '→ liste des noms précis comme boost / support / voiceJoin', '→ list exact names like boost / support / voiceJoin')}`,
    `• \`${prefix}logs enable <type>\` ${uiText(guildConfig, 'et', 'and')} \`${prefix}logs disable <type>\` ${uiText(guildConfig, 'gèrent quels événements partent', 'control which events are sent')}`
  ]));

  return embed;
}

