function applySupportPreset(guild, guildConfig, presetKey = 'clean') {
  const preset = getSupportPresetConfig(guildConfig, presetKey);
  if (!preset) return false;
  guild.support = guild.support || JSON.parse(JSON.stringify(DEFAULT_GUILD.support));
  guild.support.promptMode = preset.promptMode;
  guild.support.promptTitle = preset.promptTitle;
  guild.support.promptMessage = preset.promptMessage;
  guild.support.promptFooter = preset.promptFooter;
  guild.support.promptColor = preset.promptColor;
  guild.support.promptImageUrl = preset.promptImageUrl;
  return true;
}

function applyTextsBundlePreset(guild, guildConfig, presetKey = 'clean') {
  const preset = String(presetKey || 'clean').toLowerCase();
  const bundles = {
    clean: { welcome: 'clean', welcomeDm: 'clean', leave: 'clean', leaveDm: 'clean', boost: 'clean', support: 'clean' },
    premium: { welcome: 'premium', welcomeDm: 'premium', leave: 'premium', leaveDm: 'premium', boost: 'premium', support: 'premium' },
    community: { welcome: 'community', welcomeDm: 'community', leave: 'soft', leaveDm: 'soft', boost: 'community', support: 'community' },
    anime: { welcome: 'anime', welcomeDm: 'anime', leave: 'anime', leaveDm: 'anime', boost: 'anime', support: 'anime' },
    minimal: { welcome: 'minimal', welcomeDm: 'minimal', leave: 'minimal', leaveDm: 'minimal', boost: 'minimal', support: 'minimal' }
  };
  const selected = bundles[preset];
  if (!selected) return false;
  applyWelcomePreset(guild, guildConfig, selected.welcome);
  applyWelcomePreset(guild, guildConfig, selected.welcomeDm || selected.welcome, { dm: true });
  applyLeavePreset(guild, guildConfig, selected.leave);
  applyLeavePreset(guild, guildConfig, selected.leaveDm, { dm: true });
  applyBoostPreset(guild, guildConfig, selected.boost);
  applySupportPreset(guild, guildConfig, selected.support);
  return true;
}

function getTextTemplateVariables(guild, member) {
  const createdTimestamp = member?.user?.createdTimestamp || 0;
  const joinedTimestamp = member?.joinedTimestamp || 0;
  const daysInServer = joinedTimestamp ? Math.max(0, Math.floor((Date.now() - joinedTimestamp) / 86400000)) : 0;
  return {
    user: member?.toString?.() || `<@${member?.id || '0'}>`,
    userTag: member?.user?.tag || 'Unknown#0000',
    username: member?.user?.username || member?.user?.tag?.split('#')?.[0] || 'Unknown',
    displayName: member?.displayName || member?.user?.displayName || member?.user?.username || 'Unknown',
    server: guild?.name || 'Server',
    memberCount: guild?.memberCount || 0,
    boostCount: guild?.premiumSubscriptionCount || 0,
    boostTier: guild?.premiumTier || 0,
    createdAt: createdTimestamp ? `<t:${Math.floor(createdTimestamp / 1000)}:F>` : 'unknown',
    createdAgo: createdTimestamp ? `<t:${Math.floor(createdTimestamp / 1000)}:R>` : 'unknown',
    joinedAt: joinedTimestamp ? `<t:${Math.floor(joinedTimestamp / 1000)}:F>` : 'unknown',
    joinedAgo: joinedTimestamp ? `<t:${Math.floor(joinedTimestamp / 1000)}:R>` : 'unknown',
    daysInServer: String(daysInServer),
    joinedDuration: joinedTimestamp ? formatDuration(Date.now() - joinedTimestamp) : '',
    avatarUrl: member?.displayAvatarURL?.({ extension: 'png', size: 256 }) || '',
    serverIconUrl: guild?.iconURL?.({ extension: 'png', size: 256 }) || ''
  };
}

function isOffWord(value) {
  return ['off', 'none', 'clear', 'remove'].includes(String(value || '').toLowerCase());
}

function isDefaultWord(value) {
  return ['default', 'reset'].includes(String(value || '').toLowerCase());
}

function isValidHttpUrl(value) {
  return /^https?:\/\//i.test(String(value || '').trim());
}

function isValidHexCouleurInput(value) {
  return /^#?[0-9a-f]{6}$/i.test(String(value || '').trim());
}


function createModulePreviewMessage(guildConfig, source, variables, options = {}) {
  const titleKey = options.titleKey || 'title';
  const messageKey = options.messageKey || 'message';
  const modeKey = options.modeKey || 'mode';
  const footerKey = options.footerKey || 'footer';
  const colorKey = options.colorKey || 'color';
  const imageKey = options.imageKey || 'imageUrl';
  const fallbackTitre = options.fallbackTitre || '';
  const textValue = fillTemplate(source?.[messageKey], variables);
  const titleValue = fillTemplate(source?.[titleKey] || fallbackTitre, variables);
  const footerValue = source?.[footerKey] === null ? null : fillTemplate(source?.[footerKey] ?? 'Neyora', variables);
  const imageUrl = fillTemplate(source?.[imageKey] || '', variables);
  const render = buildAnnouncementPreviewContext(guildConfig, variables, options);
  return createAnnouncementPreviewPayload(guildConfig, {
    mode: source?.[modeKey],
    title: titleValue,
    footer: footerValue,
    color: source?.[colorKey],
    imageUrl
  }, textValue, render);
}

function getSupportPromptVariables(guild, support, prefix = '+', fallbackChannel = null) {
  return {
    server: guild?.name || 'Server',
    prefix,
    supportChannel: support?.entryChannelId ? `<#${support.entryChannelId}>` : (fallbackChannel ? `<#${fallbackChannel.id}>` : '#support')
  };
}

function createSupportPromptPayload(guildConfig, guild, prefix = '+', fallbackChannel = null) {
  const support = guildConfig.support || {};
  const vars = getSupportPromptVariables(guild, support, prefix, fallbackChannel);
  const title = fillTemplate(support.promptTitle || '📨 Need help?', vars).trim();
  const description = fillTemplate(support.promptMessage || 'To contact the staff, write in {supportChannel} or DM the bot. `{prefix}support your message` also works.', vars).trim();
  const footer = fillTemplate(support.promptFooter ?? 'Neyora Support', vars).trim();
  const imageUrl = fillTemplate(support.promptImageUrl || '', vars).trim();
  return createAnnouncementPreviewPayload(guildConfig, {
    mode: support.promptMode || 'embed',
    title,
    footer,
    color: support.promptColor,
    imageUrl
  }, description);
}

function normalizeMpallMode(value) {
  const mode = String(value || '').toLowerCase();
  return ['plain', 'simple', 'text'].includes(mode) ? 'plain' : 'embed';
}

function getMpallVariables(guild, member) {
  return {
    user: member?.toString?.() || `<@${member?.id || '0'}>`,
    userTag: member?.user?.tag || 'Unknown#0000',
    server: guild?.name || 'Server',
    memberCount: guild?.memberCount || 0
  };
}

function createMpallPayload(guildConfig, guild, member) {
  const source = guildConfig?.mpall || {};
  const vars = getMpallVariables(guild, member);
  const message = fillTemplate(source.message || '', vars).trim();
  const title = fillTemplate(source.title || '📨 Message from {server}', vars).trim();
  const footer = source.footer == null ? '' : fillTemplate(source.footer ?? 'Neyora', vars).trim();
  const imageUrl = fillTemplate(source.imageUrl || '', vars).trim();
  return createAnnouncementPreviewPayload(guildConfig, {
    mode: normalizeMpallMode(source.mode),
    title,
    footer,
    color: source.color,
    imageUrl
  }, message || 'No message set.');
}

function buildMpallModuleEmbed(guildConfig, prefix = '+') {
  const mpall = guildConfig?.mpall || {};
  const mode = normalizeMpallMode(mpall.mode);
  return baseEmbed(guildConfig, '📨 MP all', 'Mass DM module for server announcements. Configure the style once, then send it to everyone, humans only, bots only, or one role.')
    .addFields(
      {
        name: 'Current style',
        value: [
          `**Mode:** ${mode === 'plain' ? 'simple' : 'embed'}`,
          `**Titre:** ${formatTemplatePreview(mpall.title, '📨 Message from {server}')}`,
          `**Message:** ${formatTemplatePreview(mpall.message, 'not set')}`,
          `**Footer:** ${mode === 'embed' ? formatTemplatePreview(mpall.footer, 'Neyora') : 'unused in simple mode'}`,
          `**Couleur:** ${mode === 'embed' ? code(mpall.color || guildConfig?.embedColor || '#5865F2') : 'unused in simple mode'}`,
          `**Image:** ${mode === 'embed' ? formatTemplatePreview(mpall.imageUrl, 'none') : 'unused in simple mode'}`
        ].join('\n').slice(0, 1024),
        inline: false
      },
      {
        name: 'Config',
        value: [
          `\`${prefix}mpall mode embed\``,
          `\`${prefix}mpall mode simple\``,
          `\`${prefix}mpall title 📢 Important\``,
          `\`${prefix}mpall message Salut {user}, ...\``,
          `\`${prefix}mpall footer Staff\``,
          `\`${prefix}mpall color #FF4D6D\``,
          `\`${prefix}mpall image https://...\``
        ].join('\n'),
        inline: true
      },
      {
        name: 'Send',
        value: [
          `\`${prefix}mpall test\``,
          `\`${prefix}mpall send\``,
          `\`${prefix}mpall send humans\``,
          `\`${prefix}mpall send bots\``,
          `\`${prefix}mpall send @Role\``,
          `\`${prefix}mpall reset\``
        ].join('\n'),
        inline: true
      },
      {
        name: 'Variables',
        value: '`{user}` • `{userTag}` • `{server}` • `{memberCount}`',
        inline: false
      }
    );
}


function buildSupportModuleEmbed(guildConfig, prefix = '+') {
  const support = guildConfig.support || {};
  const noValue = uiText(guildConfig, 'non défini', 'not set');
  const none = uiText(guildConfig, 'aucun', 'none');
  const relayReady = Boolean(support.enabled && support.channelId);
  const entryReady = Boolean(support.entryChannelId);
  const promptReady = Boolean(String(support.promptTitle || '').trim() || String(support.promptMessage || '').trim());
  const issues = [];
  if (!relayReady) issues.push(uiText(guildConfig, '• définis le salon relais staff', '• set the staff relay channel'));
  if (!entryReady) issues.push(uiText(guildConfig, '• définis le salon membre', '• set the member channel'));
  if (!promptReady) issues.push(uiText(guildConfig, '• prépare le prompt public', '• prepare the public prompt'));
  if (support.entryCommandOnly && !support.entryChannelId) issues.push(uiText(guildConfig, '• support-only a besoin du salon membre', '• support-only needs the member channel'));

  const memberFlow = entryReady
    ? uiText(guildConfig, `Les membres écrivent dans ${uiChannel(support.entryChannelId, noValue)}, utilisent \`${prefix}support\`, ou contactent le bot en MP.`, `Members write in ${uiChannel(support.entryChannelId, noValue)}, use \`${prefix}support\`, or DM the bot.`)
    : uiText(guildConfig, `Les membres peuvent utiliser \`${prefix}support\` ou contacter le bot en MP.`, `Members can use \`${prefix}support\` or DM the bot.`);

  const embed = applyHubFrame(
    baseEmbed(
      guildConfig,
      uiText(guildConfig, '📨 Support', '📨 Support'),
      uiText(guildConfig, 'Un point clair pour le contact membre, le relais staff et le prompt public.', 'One clear place for member contact, staff relay and the public prompt.')
    ),
    guildConfig,
    null,
    'Support',
    'Support',
    [
      hubBadge(guildConfig, '👥', 'Membres', 'Members', memberFlow),
      hubBadge(guildConfig, '🧾', 'Relais', 'Relay', `${uiState(Boolean(support.enabled), uiText(guildConfig, 'actif', 'enabled'), uiText(guildConfig, 'off', 'off'))} • ${uiChannel(support.channelId, noValue)}`),
      hubBadge(guildConfig, '🔔', 'Ping', 'Ping', uiRole(support.pingRoleId, none))
    ]
  );

  embed.addFields(
    sectionField(uiText(guildConfig, '📍 État actuel', '📍 Current state'), [
      metricLine(uiText(guildConfig, 'Salon membre', 'Member channel'), uiChannel(support.entryChannelId, noValue)),
      metricLine(uiText(guildConfig, 'Relais staff', 'Staff relay'), uiChannel(support.channelId, noValue)),
      metricLine(uiText(guildConfig, 'Restriction', 'Restriction'), uiBool(support.restrictToEntry, uiText(guildConfig, 'oui', 'yes'), uiText(guildConfig, 'non', 'no'))),
      metricLine(uiText(guildConfig, 'Support-only', 'Support-only'), uiBool(support.entryCommandOnly, uiText(guildConfig, 'oui', 'yes'), uiText(guildConfig, 'non', 'no')))
    ], false),
    sectionField(uiText(guildConfig, '⚡ Le plus utile', '⚡ Most useful'), [
      commandPill(prefix, 'support panel'),
      commandPill(prefix, 'support quicksetup #support-logs'),
      commandPill(prefix, 'support preview'),
      commandPill(prefix, 'support send'),
      commandPill(prefix, 'support test')
    ], true),
    sectionField(uiText(guildConfig, '💬 Côté membres', '💬 Member side'), [
      uiText(guildConfig, '• écrire directement dans le salon support', '• write directly in the support channel'),
      `• ${commandPill(prefix, 'support Bonjour')}`,
      uiText(guildConfig, '• contacter le bot en MP', '• DM the bot directly'),
      `• ${commandPill(prefix, 'reply @user Bonjour')}`
    ], true),
    sectionField(uiText(guildConfig, '🩺 À finir', '🩺 Needs attention'), issues.length ? issues : uiText(guildConfig, '• setup propre, tu peux tester le flux', '• setup looks clean, you can test the flow'))
  );

  return translateEmbedForUi(guildConfig, embed);
}

