function buildPrivateLogOverwrites(guild) {
  if (!guild?.roles?.everyone?.id || !guild?.members?.me?.id) return [];
  return [
    {
      id: guild.roles.everyone.id,
      deny: [PermissionFlagsBits.ViewChannel]
    },
    {
      id: guild.members.me.id,
      allow: [PermissionFlagsBits.ViewChannel, PermissionFlagsBits.SendMessages, PermissionFlagsBits.EmbedLinks, PermissionFlagsBits.AttachFiles, PermissionFlagsBits.ReadMessageHistory]
    }
  ];
}

async function ensureNamedTextChannel(guild, name, parentId, reason) {
  const safeName = String(name || 'logs').toLowerCase().slice(0, 100);
  let channel = guild.channels.cache.find((entry) => entry?.parentId === parentId && isLogsTextChannel(entry) && entry.name === safeName) || null;
  if (!channel) {
    channel = await guild.channels.create({
      name: safeName,
      type: ChannelType.GuildText,
      parent: parentId || null,
      permissionOverwrites: buildPrivateLogOverwrites(guild),
      reason: reason || 'Neyora channel setup'
    }).catch(() => null);
  }
  return channel;
}

async function setupLogsBundle(ctx, categoryName = '🧾 Logs') {
  const guild = ctx.guild;
  const logs = ctx.guildConfig.logs || { enabled: false, channelId: null, channels: {}, typeSalons: {}, types: {} };
  const knownRouteIds = [
    logs.channels?.default || logs.channelId || null,
    logs.channels?.messages || null,
    logs.channels?.members || null,
    logs.channels?.moderation || null,
    logs.channels?.voice || null,
    logs.channels?.server || null,
    logs.channels?.social || null
  ].filter(Boolean);

  let category = null;
  for (const channelId of knownRouteIds) {
    const channel = guild.channels.cache.get(channelId) || await guild.channels.fetch(channelId).catch(() => null);
    if (channel?.parent?.type === ChannelType.GuildCategory) {
      category = channel.parent;
      break;
    }
  }

  if (!category) {
    category = guild.channels.cache.find((entry) => entry?.type === ChannelType.GuildCategory && /log/i.test(entry.name)) || null;
  }

  if (!category) {
    category = await guild.channels.create({
      name: String(categoryName || '🧾 Logs').slice(0, 100),
      type: ChannelType.GuildCategory,
      permissionOverwrites: buildPrivateLogOverwrites(guild),
      reason: `Neyora logs setup by ${ctx.user.tag}`
    }).catch(() => null);
  }

  if (!category) return null;
  await category.permissionOverwrites.set(buildPrivateLogOverwrites(guild)).catch(() => null);

  const plan = [
    ['default', 'logs'],
    ['messages', 'message-logs'],
    ['members', 'member-logs'],
    ['moderation', 'mod-logs'],
    ['voice', 'voice-logs'],
    ['server', 'server-logs'],
    ['social', 'social-logs']
  ];

  const created = {};
  for (const [key, fallbackName] of plan) {
    const existingId = key === 'default' ? (logs.channels?.default || logs.channelId || null) : (logs.channels?.[key] || null);
    let channel = existingId ? (guild.channels.cache.get(existingId) || await guild.channels.fetch(existingId).catch(() => null)) : null;
    if (!isLogsTextChannel(channel)) {
      channel = await ensureNamedTextChannel(guild, fallbackName, category.id, `Neyora logs setup by ${ctx.user.tag}`);
    }
    if (channel && channel.parentId !== category.id) await channel.setParent(category.id).catch(() => null);
    if (channel) await channel.permissionOverwrites.set(buildPrivateLogOverwrites(guild)).catch(() => null);
    created[key] = channel || null;
  }

  ctx.store.updateGuild(ctx.guild.id, (guildConfig) => {
    guildConfig.logs = guildConfig.logs || { enabled: false, channelId: null, channels: {}, typeSalons: {}, types: {} };
    guildConfig.logs.enabled = true;
    guildConfig.logs.channels = guildConfig.logs.channels || { default: null, messages: null, members: null, moderation: null, voice: null, server: null, social: null };
    guildConfig.logs.channels.default = created.default?.id || null;
    guildConfig.logs.channelId = created.default?.id || null;
    guildConfig.logs.channels.messages = created.messages?.id || null;
    guildConfig.logs.channels.members = created.members?.id || null;
    guildConfig.logs.channels.moderation = created.moderation?.id || null;
    guildConfig.logs.channels.voice = created.voice?.id || null;
    guildConfig.logs.channels.server = created.server?.id || null;
    guildConfig.logs.channels.social = created.social?.id || null;
    guildConfig.logs.types = guildConfig.logs.types || {};
    return guildConfig;
  });

  return { category, channels: created };
}

function createActionCommand(name, emoji, verbs, aliases, templates) {
  return makeSimpleCommand({
    name,
    aliases,
    category: 'Action',
    description: `${name} someone with a GIF`,
    usage: `${name} @member|id`,
    guildOnly: true,
    slash: {
      root: 'action',
      sub: name,
      description: `${name} a member`,
      options: [{ type: 'user', name: 'target', description: 'Target member', required: true }]
    },
    async execute(ctx) {
      const target = await ctx.getMember('target', 0);
      if (!target) return ctx.invalidUsage(`Try \`${ctx.prefix}${name} @user\``);
      const template = randomOf(templates);
      const verb = randomOf(verbs);
      const description = template
        .replace('{author}', ctx.member.toString())
        .replace('{target}', target.toString())
        .replace('{verb}', verb);
      const embed = baseEmbed(ctx.guildConfig, `${emoji} ${name.toUpperCase()}`, description);
      await ctx.reply({ embeds: [embed] });
    }
  });
}

function createTransformCommand(name, description, usage, aliases, fn) {
  return makeSimpleCommand({
    name,
    aliases,
    category: 'Utility',
    description,
    usage,
    dmAllowed: true,
    slash: {
      root: 'utility',
      sub: name,
      description,
      options: [{ type: 'string', name: 'text', description: 'Text', required: true }]
    },
    async execute(ctx) {
      const text = ctx.interaction ? ctx.interaction.options.getString('text') : ctx.getRest(0);
      if (!text) return ctx.invalidUsage();
      await ctx.reply({ embeds: [baseEmbed(ctx.guildConfig, `🛠️ ${name}`, String(fn(text)).slice(0, 4090))] });
    }
  });
}

function createToggleCommand(name, description, path, aliases = []) {
  return makeSimpleCommand({
    name,
    aliases,
    category: 'Security',
    description,
    usage: `${name} on|off`,
    guildOnly: true,
    userPermissions: [PermissionFlagsBits.ManageGuild],
    slash: {
      root: 'security',
      sub: name,
      description,
      options: [{
        type: 'string',
        name: 'state',
        description: 'on / off',
        required: true,
        choices: [{ name: 'on', value: 'on' }, { name: 'off', value: 'off' }]
      }]
    },
    async execute(ctx) {
      const state = (ctx.getText('state', 0) || '').toLowerCase();
      if (!['on', 'off'].includes(state)) return ctx.invalidUsage();
      ctx.store.updateGuild(ctx.guild.id, (guild) => {
        const parts = path.split('.');
        let ref = guild;
        for (let i = 0; i < parts.length - 1; i++) ref = ref[parts[i]];
        ref[parts.at(-1)] = state === 'on';
        return guild;
      });
      await ctx.reply({ embeds: [baseEmbed(ctx.guildConfig, '🚨 Security', `**${name}** is now **${state}**.`)] });
    }
  });
}

function ownerBase(name, description, usage, aliases, options, execute) {
  return makeSimpleCommand({
    name,
    aliases,
    category: 'Owner',
    description,
    usage,
    ownerOnly: true,
    slash: {
      root: 'owner',
      sub: name,
      description,
      options
    },
    async execute(ctx) {
      await execute(ctx);
    }
  });
}

function getCommandLookup(client, query) {
  const raw = String(query || '').trim().replace(/^[+/]/, '').toLowerCase();
  if (!raw) return null;
  return client.commandRegistry.find((cmd) => cmd.name === raw || (cmd.aliases || []).includes(raw)) || null;
}

function formatPermissionLabel(permission) {
  const entry = Object.entries(PermissionFlagsBits).find(([, value]) => value === permission);
  const raw = entry?.[0] || String(permission || '');
  return raw.replace(/([a-z0-9])([A-Z])/g, '$1 $2').replace(/Guild/g, 'Server').trim();
}

function formatCommandAccess(command, guildConfig = null) {
  const scope = command.guildOnly
    ? uiText(guildConfig, 'Serveur uniquement', 'Server only')
    : (command.dmAllowed ? uiText(guildConfig, 'MP + serveur', 'DM + server') : uiText(guildConfig, 'Serveur par défaut', 'Server by default'));
  const perms = command.userPermissions?.length
    ? command.userPermissions.map(formatPermissionLabel).join(', ')
    : uiText(guildConfig, 'Aucune permission spéciale', 'No special permission');
  return { scope, perms };
}

function getCommandHelpUsage(command) {
  return String(command?.helpUsageShort || command?.usage || command?.name || '').trim();
}

function renderHelpGuideLine(prefix, line) {
  const rendered = String(line || '').replace(/\{prefix\}/g, prefix).trim();
  if (!rendered) return null;
  return rendered.includes(prefix) ? `• \`${rendered}\`` : `• ${rendered}`;
}

function normalizeHelpSyntaxGroups(command, guildConfig, prefix) {
  const explicit = Array.isArray(command?.helpSyntaxGroups) ? command.helpSyntaxGroups : [];
  const source = explicit.length
    ? explicit
    : (Array.isArray(command?.helpQuickSections) ? command.helpQuickSections.map((section) => ({
        labelFr: section.titleFr || section.title || 'Section',
        labelEn: section.titleEn || section.title || 'Section',
        lines: section.lines || []
      })) : []);
  return source.map((group) => {
    const name = uiText(guildConfig, group.labelFr || group.titleFr || group.label || group.title || 'Section', group.labelEn || group.titleEn || group.label || group.title || 'Section');
    const lines = (group.lines || []).map((line) => renderHelpGuideLine(prefix, line)).filter(Boolean).slice(0, group.limit || 4);
    return { name, lines, inline: group.inline !== false };
  }).filter((group) => group.lines.length);
}

function getCommandHelpSections(command, guildConfig, prefix) {
  return normalizeHelpSyntaxGroups(command, guildConfig, prefix).map((group) => ({
    name: group.name,
    value: group.lines.join('\n').slice(0, 1024),
    inline: group.inline !== false
  })).filter((section) => section.value);
}

function formatInvalidUsageText(command, guildConfig, prefix, extra = '') {
  const usageLabel = uiText(guildConfig, 'À taper', 'What to type');
  const quickLabel = uiText(guildConfig, 'Commandes utiles', 'Useful commands');
  const examplesLabel = uiText(guildConfig, 'Exemples', 'Examples');
  const aliasesLabel = uiText(guildConfig, 'Alias', 'Aliases');
  const groups = normalizeHelpSyntaxGroups(command, guildConfig, prefix);
  const quickLines = groups.slice(0, 3).flatMap((group) => {
    const compactTitle = String(group.name || '').replace(/^[^\wÀ-ÿ]+/u, '').trim();
    const head = compactTitle ? [`**${compactTitle}**`] : [];
    return [...head, ...group.lines.slice(0, 3)];
  }).slice(0, 10);
  const exampleLines = quickExamplesForCommand(command, prefix).slice(0, 3).map((entry) => `• \`${entry}\``);
  const aliasLine = command.aliases?.length ? `${aliasesLabel} • ${command.aliases.slice(0, 4).map((alias) => `\`${prefix}${alias}\``).join(' • ')}` : null;
  return [
    `${usageLabel} • ${commandPill(prefix, getCommandHelpUsage(command))}`,
    command.helpIntro || command.description || null,
    quickLines.length ? `
**${quickLabel}**
${quickLines.join('\n')}` : null,
    exampleLines.length ? `
**${examplesLabel}**
${exampleLines.join('\n')}` : null,
    extra ? `
${extra}` : null,
    aliasLine
  ].filter(Boolean).join('\n');
}

function createCommandHelpEmbed(client, guildConfig, command) {
  const prefix = guildConfig?.prefix || '+';
  const access = formatCommandAccess(command, guildConfig);
  const slashText = command.slash ? `/${command.slash.root} ${command.slash.sub}` : null;
  const usage = commandPill(prefix, getCommandHelpUsage(command));
  const aliasList = command.aliases?.slice(0, 4) || [];
  const syntaxGroups = normalizeHelpSyntaxGroups(command, guildConfig, prefix);
  const examples = quickExamplesForCommand(command, prefix).slice(0, 4).map((line) => `• \`${line}\``);
  const descriptionIntro = command.helpIntro || command.description || uiText(guildConfig, 'Aucune description.', 'No description.');
  const relatedByCategory = {
    General: ['help', 'guide', 'start'],
    Info: ['info', 'profile', 'serverinfo'],
    Utility: ['utility', 'calc', 'choose'],
    Support: ['support', 'reply', 'guide support'],
    Confessions: ['confession', 'confessions', 'help members'],
    Moderation: ['moderation', 'warnings', 'clear'],
    Security: ['security', 'automodconfig', 'wl list'],
    Logs: ['logs panel', 'logs view', 'logtypes'],
    Roles: ['roles', 'autorole', 'statusroleconfig'],
    Tracking: ['tracking', 'stats', 'inviteleaderboard'],
    Voice: ['voice', 'voicepanel', 'createvoc'],
    Welcome: ['welcome', 'leave', 'boost'],
    Config: ['setup', 'custom', 'preset'],
    System: ['dashboard', 'panel', 'ready'],
    Progress: ['trophy', 'trophyconfig', 'milestoneconfig'],
    Automation: ['automation', 'stickyconfig', 'autoreact'],
    Giveaway: ['giveaway', 'glist', 'gparticipants'],
    TikTok: ['tiktok', 'tiktoklist', 'tiktoktest'],
    Permissions: ['permconfig', 'permrole', 'permcmd'],
    Owner: ['backup', 'repair', 'ready']
  };
  const related = (relatedByCategory[command.category] || [])
    .filter((entry) => !entry.toLowerCase().startsWith(String(command.name || '').toLowerCase()))
    .slice(0, 3)
    .map((entry) => `• ${commandPill(prefix, entry)}`);

  const embed = brandEmbed(guildConfig, uiText(guildConfig, `📘 ${prefix}${command.name}`, `📘 ${prefix}${command.name}`), [
    descriptionIntro,
    '',
    hubBadge(guildConfig, '🗂️', 'Catégorie', 'Category', `${CATEGORY_META[command.category]?.emoji || '•'} ${categoryLabelFor(guildConfig, command.category)}`),
    hubBadge(guildConfig, '🧭', 'Accès', 'Access', access.scope),
    hubBadge(guildConfig, '🔐', 'Permissions', 'Permissions', access.perms)
  ].join('\n'));

  embed.addFields(sectionField(uiText(guildConfig, '🧩 À taper', '🧩 What to type'), [
    usage,
    slashText ? `${uiText(guildConfig, 'Slash', 'Slash')} • \`${slashText}\`` : null,
    aliasList.length ? `${uiText(guildConfig, 'Alias', 'Aliases')} • ${aliasList.map((alias) => commandPill(prefix, alias)).join(' • ')}` : null
  ]));

  syntaxGroups.slice(0, 3).forEach((group) => {
    embed.addFields(sectionField(group.name, group.lines, group.inline !== false));
  });

  if (examples.length) {
    embed.addFields(sectionField(uiText(guildConfig, '🧪 Exemples', '🧪 Examples'), examples, false));
  }

  if (related.length) {
    embed.addFields(sectionField(uiText(guildConfig, '🔗 Aller plus loin', '🔗 Continue with'), related, false));
  }

  embed.setFooter({ text: uiText(guildConfig, 'Neyora • fiche commande', 'Neyora • command card') });
  return applyEmbedVisualStyle(embed, guildConfig);
}


function chunkLines(lines, size = 12) {
  const chunks = [];
  for (let i = 0; i < lines.length; i += size) chunks.push(lines.slice(i, i + size));
  return chunks.length ? chunks : [[]];
}

function buildHelpLine(prefix, cmd, category = null, guildConfig = null) {
  const summary = clipText(cmd.helpIntro || cmd.description || uiText(guildConfig, 'Commande disponible.', 'Available command.'), category === 'All' ? 70 : 84);
  const usage = clipText(getCommandHelpUsage(cmd), 54);
  const categoryText = category === 'All' ? ` • ${CATEGORY_META[cmd.category]?.emoji || '•'} ${categoryLabelFor(guildConfig, cmd.category)}` : '';
  const usageText = usage && usage !== cmd.name ? `
↳ \`${prefix}${usage}\`` : '';
  return `• **${commandPill(prefix, cmd.name)}**${categoryText}${usageText}
↳ ${summary}`;
}


function getSetupHelpPages() {
  const entries = Object.entries(CONFIG_HELP_GROUPS);
  const pages = [];
  for (let i = 0; i < entries.length; i += SETUP_GROUPS_PER_PAGE) pages.push(entries.slice(i, i + SETUP_GROUPS_PER_PAGE));
  return pages.length ? pages : [[]];
}

