          titleFr: 'Giveaway déjà terminé',
          tone: 'warning',
          summary: `Giveaway **${target.id}** is already ended, so it cannot be resumed.`,
          stateLines: buildGiveawayStateLines(ctx.guildConfig, target.giveaway, target.id)
